def design_rag_support_system() -> dict:
    """Design a complete RAG-based customer support system.

    Returns a structured design document as a dictionary with keys:
    - requirements
    - components
    - data_flow
    - api_design
    - storage
    - evaluation
    """
    design = {}

    # Step 1: Requirements
    design['requirements'] = {
        'functional': [
            'Accept customer support queries via text input',
            'Retrieve relevant documentation from knowledge base using semantic search',
            'Generate grounded responses with inline citations to source documents',
            'Detect queries requiring human escalation (low confidence, sensitive topics, explicit request)',
            'Maintain multi-turn conversation history for contextual follow-ups',
            'Support intent classification for routing (billing, technical, account, general)'
        ],
        'non_functional': {
            'latency_p50_ms': 1500,
            'latency_p99_ms': 4000,
            'time_to_first_token_ms': 500,
            'throughput_rps': 50,
            'cost_per_request_usd': 0.02,
            'availability': 0.999
        },
        'quality_metrics': [
            {'name': 'answer_accuracy', 'target': 0.92, 'measurement_method': 'weekly human evaluation on 200-query sample'},
            {'name': 'citation_precision', 'target': 0.95, 'measurement_method': 'automated source verification against retrieved passages'},
            {'name': 'hallucination_rate', 'target': 0.02, 'measurement_method': 'automated grounding check plus human audit'},
            {'name': 'escalation_appropriateness', 'target': 0.90, 'measurement_method': 'human review of escalated and non-escalated queries'},
            {'name': 'user_satisfaction', 'target': 4.2, 'measurement_method': 'post-interaction CSAT survey (1-5 scale)'}
        ]
    }

    # Step 2: Components
    design['components'] = [
        {'name': 'Intent Classifier', 'type': 'llm_small', 'purpose': 'Classify user queries into intent categories and detect escalation triggers', 'latency_ms': 80},
        {'name': 'Embedding Model', 'type': 'embedding_model', 'purpose': 'Convert queries and documents to dense vector representations for semantic search', 'latency_ms': 30},
        {'name': 'Semantic Cache', 'type': 'cache', 'purpose': 'Cache responses for semantically similar queries to reduce latency and cost', 'latency_ms': 5},
        {'name': 'Knowledge Base Vector Store', 'type': 'vector_db', 'purpose': 'Store and retrieve documentation embeddings for RAG', 'latency_ms': 40},
        {'name': 'Cross-Encoder Reranker', 'type': 'reranker', 'purpose': 'Rerank retrieved passages for higher citation precision', 'latency_ms': 100},
        {'name': 'Response Generator', 'type': 'llm_large', 'purpose': 'Generate grounded responses with citations from retrieved context', 'latency_ms': 1200},
        {'name': 'Output Guardrail', 'type': 'guardrail', 'purpose': 'Check responses for policy hallucinations, PII leakage, and compliance violations', 'latency_ms': 60},
        {'name': 'Escalation Queue', 'type': 'queue', 'purpose': 'Route escalated queries to human agents with full context', 'latency_ms': 10}
    ]

    # Step 3: Data Flow
    design['data_flow'] = [
        {'step_name': 'parse_and_validate', 'component': 'Query Parser', 'input': 'raw_user_message', 'output': 'validated_query', 'latency_ms': 10},
        {'step_name': 'classify_intent', 'component': 'Intent Classifier', 'input': 'validated_query', 'output': 'intent_label_and_confidence', 'latency_ms': 80},
        {'step_name': 'embed_query', 'component': 'Embedding Model', 'input': 'validated_query', 'output': 'query_embedding', 'latency_ms': 30},
        {'step_name': 'check_cache', 'component': 'Semantic Cache', 'input': 'query_embedding', 'output': 'cached_response_or_miss', 'latency_ms': 5},
        {'step_name': 'retrieve_documents', 'component': 'Knowledge Base Vector Store', 'input': 'query_embedding_and_intent', 'output': 'candidate_passages', 'latency_ms': 40},
        {'step_name': 'rerank_passages', 'component': 'Cross-Encoder Reranker', 'input': 'query_and_candidate_passages', 'output': 'top_5_ranked_passages', 'latency_ms': 100},
        {'step_name': 'generate_response', 'component': 'Response Generator', 'input': 'query_and_ranked_passages_and_history', 'output': 'response_with_citations', 'latency_ms': 1200},
        {'step_name': 'check_guardrails', 'component': 'Output Guardrail', 'input': 'generated_response', 'output': 'approved_or_flagged_response', 'latency_ms': 60},
        {'step_name': 'route_or_deliver', 'component': 'Escalation Queue / Response Delivery', 'input': 'approved_response_or_escalation', 'output': 'final_response_to_user', 'latency_ms': 10}
    ]

    # Step 4: API Design
    design['api_design'] = {
        'endpoints': [
            {'method': 'POST', 'path': '/api/v1/support/query', 'description': 'Submit a support query and receive a streamed response'},
            {'method': 'GET', 'path': '/api/v1/support/conversations/{id}', 'description': 'Retrieve conversation history'},
            {'method': 'POST', 'path': '/api/v1/support/feedback', 'description': 'Submit user feedback on a response'},
            {'method': 'POST', 'path': '/api/v1/support/escalate', 'description': 'Manually escalate to human agent'}
        ],
        'request_schema': {
            'query': 'string (required) - the user message',
            'conversation_id': 'string (optional) - for multi-turn context',
            'user_context': 'object (optional) - account tier, product, locale',
            'stream': 'boolean (default true) - enable SSE streaming'
        },
        'response_schema': {
            'response_id': 'string - unique response identifier',
            'content': 'string - the generated response text',
            'citations': 'array of {source_title, source_url, passage} objects',
            'confidence': 'float - system confidence in response quality',
            'intent': 'string - classified intent category',
            'escalated': 'boolean - whether query was escalated to human',
            'metadata': 'object with latency_ms, model_used, tokens_used'
        }
    }

    # Step 5: Storage
    design['storage'] = {
        'vector_store': {
            'technology': 'Pinecone or pgvector',
            'purpose': 'Store documentation embeddings for semantic retrieval',
            'schema_description': 'Vectors with metadata: doc_id, chunk_text, source_url, category, last_updated'
        },
        'conversation_store': {
            'technology': 'PostgreSQL',
            'purpose': 'Store conversation history, messages, and metadata for multi-turn context',
            'schema_description': 'Tables: conversations(id, user_id, created_at, status), messages(id, conversation_id, role, content, citations, timestamp)'
        },
        'cache': {
            'technology': 'Redis with vector similarity plugin',
            'purpose': 'Semantic cache for similar queries and exact-match cache for identical queries',
            'schema_description': 'Key: query_embedding, Value: response + citations + TTL(24h), similarity_threshold: 0.95'
        },
        'evaluation_store': {
            'technology': 'PostgreSQL + S3',
            'purpose': 'Store all request-response pairs with metadata for evaluation and retraining',
            'schema_description': 'request_log(id, query, intent, retrieved_docs, response, citations, confidence, latency_ms, user_feedback, timestamp)'
        }
    }

    # Step 6: Evaluation
    design['evaluation'] = {
        'offline': {
            'test_set_size': 500,
            'metrics': ['answer_accuracy', 'citation_precision', 'hallucination_rate', 'intent_classification_f1'],
            'run_frequency': 'on every prompt or model change, before deployment'
        },
        'online': {
            'metrics': [
                'latency_p50_p99',
                'error_rate',
                'cache_hit_rate',
                'escalation_rate',
                'user_feedback_thumbs_up_ratio',
                'response_regeneration_rate'
            ]
        },
        'quality_gates': [
            {'metric': 'answer_accuracy', 'threshold': 0.90, 'action': 'block deployment if below threshold'},
            {'metric': 'hallucination_rate', 'threshold': 0.03, 'action': 'block deployment if above threshold'},
            {'metric': 'latency_p99', 'threshold': 4500, 'action': 'alert and block if p99 exceeds 4500ms'},
            {'metric': 'citation_precision', 'threshold': 0.93, 'action': 'block deployment if below threshold'}
        ]
    }

    return design

# Test your design
result = design_rag_support_system()
for key in result:
    print(f"{key}: {type(result[key]).__name__}")

