def design_code_review_system() -> dict:
    """Design a multi-agent code review system.

    Returns a structured design document as a dictionary with keys:
    - requirements
    - agents
    - coordination
    - data_flow
    - integration
    - evaluation
    """
    design = {}

    # Step 1: Requirements
    design['requirements'] = {
        'functional': [
            'Analyze pull request diffs for security vulnerabilities, style violations, and logic errors',
            'Generate actionable review comments with specific code suggestions and line references',
            'Prioritize findings by severity (critical, warning, suggestion)',
            'Deduplicate findings when multiple reviewers flag the same issue',
            'Integrate with Git hosting platforms (GitHub/GitLab) via webhook triggers',
            'Support project-specific configuration for style rules and security policies'
        ],
        'non_functional': {
            'total_review_time_seconds': 120,
            'max_review_time_seconds': 300,
            'throughput_reviews_per_minute': 10,
            'cost_per_review_usd': 0.30,
            'max_findings_per_review': 25
        },
        'quality_metrics': [
            {'name': 'precision', 'target': 0.85, 'measurement_method': 'weekly sample of 50 reviews rated by senior engineers'},
            {'name': 'recall', 'target': 0.60, 'measurement_method': 'comparison against human reviewer findings on same PRs'},
            {'name': 'false_positive_rate', 'target': 0.15, 'measurement_method': 'developer dismiss rate on findings'},
            {'name': 'actionability_score', 'target': 0.80, 'measurement_method': 'fraction of findings that include valid code suggestions'}
        ]
    }

    # Step 2: Agents
    design['agents'] = [
        {
            'name': 'Coordinator',
            'role': 'coordinator',
            'model_size': 'large',
            'system_prompt_summary': 'Analyze PR diff to create a review plan. Determine which files need security, style, and logic review based on change patterns. After receiving specialist reports, aggregate findings, resolve conflicts, deduplicate, and produce the final review.',
            'output_schema': {
                'review_plan': 'object with file assignments per specialist',
                'final_review': 'list of deduplicated, prioritized findings'
            }
        },
        {
            'name': 'Security Reviewer',
            'role': 'security_reviewer',
            'model_size': 'large',
            'system_prompt_summary': 'Review code for security vulnerabilities: SQL injection, XSS, CSRF, hardcoded secrets, insecure deserialization, authentication/authorization flaws, SSRF, path traversal. Reference OWASP Top 10. Focus on code that handles user input, database queries, authentication, file I/O, and network requests.',
            'output_schema': {
                'findings': 'list of {file, line_range, vulnerability_type, severity, description, remediation, cwe_id}'
            }
        },
        {
            'name': 'Style Reviewer',
            'role': 'style_reviewer',
            'model_size': 'small',
            'system_prompt_summary': 'Review code for style and readability: naming conventions, documentation completeness, function length, code duplication, consistent formatting, proper error messages, appropriate abstractions. Reference project style guide if provided.',
            'output_schema': {
                'findings': 'list of {file, line_range, style_rule, severity, description, suggestion}'
            }
        },
        {
            'name': 'Logic Reviewer',
            'role': 'logic_reviewer',
            'model_size': 'large',
            'system_prompt_summary': 'Review code for correctness and robustness: off-by-one errors, null/undefined handling, race conditions, resource leaks, edge cases, error handling completeness, algorithmic complexity issues, incorrect assumptions.',
            'output_schema': {
                'findings': 'list of {file, line_range, issue_type, severity, description, example_failing_case, suggestion}'
            }
        }
    ]

    # Step 3: Coordination
    design['coordination'] = {
        'dispatch_strategy': 'Coordinator analyzes the PR diff and assigns files to specialists based on content type. Security reviewer gets files touching auth, DB, user input, and network. Style reviewer gets all modified files. Logic reviewer gets files with complex algorithmic changes. Files may be assigned to multiple specialists.',
        'aggregation_strategy': 'Coordinator collects findings from all specialists, deduplicates by file+line_range (keeping highest severity), merges related findings that reference the same root cause, and ranks final findings by severity then file order.',
        'conflict_resolution': 'When two specialists flag the same code with different recommendations, the coordinator uses the large model to evaluate both suggestions in context and selects the more appropriate one, or synthesizes a combined recommendation.',
        'timeout_handling': 'Each specialist has a 60-second timeout. If a specialist times out, the coordinator proceeds with available results and notes which review categories are incomplete. The timed-out review is retried asynchronously.'
    }

    # Step 4: Data Flow
    design['data_flow'] = [
        {'step_name': 'receive_webhook', 'component': 'Webhook Handler', 'input': 'PR creation/update event', 'output': 'PR metadata and diff', 'latency_ms': 100},
        {'step_name': 'fetch_full_diff', 'component': 'Git API Client', 'input': 'PR metadata', 'output': 'full diff with file contents', 'latency_ms': 500},
        {'step_name': 'create_review_plan', 'component': 'Coordinator Agent', 'input': 'full diff', 'output': 'file assignments per specialist', 'latency_ms': 5000},
        {'step_name': 'security_review', 'component': 'Security Reviewer Agent', 'input': 'assigned files + security context', 'output': 'security findings', 'latency_ms': 20000},
        {'step_name': 'style_review', 'component': 'Style Reviewer Agent', 'input': 'assigned files + style guide', 'output': 'style findings', 'latency_ms': 10000},
        {'step_name': 'logic_review', 'component': 'Logic Reviewer Agent', 'input': 'assigned files + codebase context', 'output': 'logic findings', 'latency_ms': 25000},
        {'step_name': 'aggregate_and_deduplicate', 'component': 'Coordinator Agent', 'input': 'all specialist findings', 'output': 'deduplicated prioritized findings', 'latency_ms': 8000},
        {'step_name': 'post_review', 'component': 'Git API Client', 'input': 'final review findings', 'output': 'PR review comments posted', 'latency_ms': 500}
    ]

    # Step 5: Integration
    design['integration'] = {
        'trigger': 'GitHub/GitLab webhook on pull_request.opened and pull_request.synchronize events. Reviews are triggered automatically on new PRs and when new commits are pushed to existing PRs.',
        'output_format': 'Individual review comments posted as inline PR comments at the relevant file and line. A summary comment is posted on the PR with a table of all findings grouped by severity. Critical findings block merge via required status check.',
        'priority_levels': [
            {'level': 'critical', 'description': 'Security vulnerabilities, data loss risks, correctness bugs', 'action': 'blocks merge'},
            {'level': 'warning', 'description': 'Potential issues, missing error handling, performance concerns', 'action': 'requires acknowledgment'},
            {'level': 'suggestion', 'description': 'Style improvements, naming, documentation', 'action': 'informational only'}
        ],
        'developer_feedback_loop': 'Developers can react to review comments with thumbs-up (valid finding) or thumbs-down (false positive). This feedback is logged and used to: (1) compute precision metrics per reviewer agent, (2) fine-tune the coordinator aggregation to filter out common false positive patterns, (3) update specialist system prompts with examples of false positives to avoid.'
    }

    # Step 6: Evaluation
    design['evaluation'] = {
        'offline': {
            'test_set_size': 200,
            'test_set_description': '200 PRs with human-annotated ground truth findings covering security, style, and logic categories',
            'metrics': ['precision_per_category', 'recall_per_category', 'false_positive_rate', 'finding_actionability'],
            'run_frequency': 'on every prompt change or model update'
        },
        'online': {
            'metrics': [
                'review_completion_time_seconds',
                'findings_per_review',
                'developer_dismiss_rate',
                'developer_acceptance_rate',
                'critical_findings_per_100_reviews',
                'agent_timeout_rate'
            ]
        },
        'quality_gates': [
            {'metric': 'precision', 'threshold': 0.80, 'action': 'block prompt/model deployment if precision drops below 80%'},
            {'metric': 'false_positive_rate', 'threshold': 0.20, 'action': 'alert and investigate if false positive rate exceeds 20%'},
            {'metric': 'review_completion_time', 'threshold': 300, 'action': 'alert if p95 review time exceeds 300 seconds'}
        ]
    }

    return design

# Test your design
result = design_code_review_system()
for key in result:
    print(f"{key}: {type(result[key]).__name__}")
